  static async customizeThemeDraft(tenantId: string, themeId: string, customConfig: CustomizeThemeInput) {
    validateCustomization(customConfig);

    let theme = await prisma.theme.findFirst({
      where: {
        id: themeId,
        OR: [{ tenantId }, { tenantId: null }],
      },
    });

    if (!theme) {
      throw new Error('Customizable tenant theme not found');
    }

    if (theme.tenantId === null) {
      theme = await prisma.theme.create({
        data: {
          tenantId,
          name: `${theme.name} Custom`,
          settings: theme.settings || '{}',
          draftSettings: theme.settings || '{}',
          isCustom: true,
        },
      });

      await prisma.website.updateMany({
        where: { tenantId, themeId: themeId },
        data: { themeId: theme.id },
      });
    }

    let baseSettings: Record<string, any> = {};
    try {
      baseSettings = JSON.parse(theme.draftSettings || theme.settings || '{}');
    } catch {
      baseSettings = {};
    }

    const updatedSettings = {
      ...baseSettings,
      ...customConfig,
      colors: {
        ...(baseSettings.colors || {}),
        ...(customConfig.colors || {}),
      },
      fonts: {
        ...(baseSettings.fonts || {}),
        ...(customConfig.fonts || {}),
      },
      logos: {
        ...(baseSettings.logos || {}),
        ...(customConfig.logos || {}),
      },
      layout: {
        ...(baseSettings.layout || {}),
        ...(customConfig.layout || {}),
      },
    };

    return await prisma.theme.update({
      where: { id: theme.id },
      data: {
        draftSettings: JSON.stringify(updatedSettings),
      },
    });
  }

